CREATE OR REPLACE FUNCTION public.apply_stock_change(p_item_id text, p_warehouse_id text, p_delta integer)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_stock jsonb;
  v_current integer;
  v_next integer;
begin
  if public.current_app_user_id() is null then
    raise exception 'authentication required';
  end if;
  if nullif(p_warehouse_id, '') is null then
    raise exception 'warehouse id is required';
  end if;

  select coalesce(stock_by_warehouse, '{}'::jsonb)
    into v_stock
  from public.items
  where id = p_item_id
  for update;
  if not found then
    raise exception 'item not found: %', p_item_id;
  end if;

  v_current := coalesce((v_stock ->> p_warehouse_id)::integer, 0);
  v_next := v_current + p_delta;
  if v_next < 0 then
    raise exception 'insufficient stock for item %, warehouse %: available %, delta %',
      p_item_id, p_warehouse_id, v_current, p_delta;
  end if;

  v_stock := jsonb_set(v_stock, array[p_warehouse_id], to_jsonb(v_next), true);

  update public.items
  set stock_by_warehouse = v_stock
  where id = p_item_id;

  return v_stock;
end;
$function$

CREATE OR REPLACE FUNCTION public.execute_ai_query(query_text text)
 RETURNS json
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  result JSON;
  upper_query TEXT;
  clean_query TEXT;
BEGIN
  -- Strip trailing semicolons and whitespace
  clean_query := RTRIM(TRIM(query_text), ';');
  clean_query := TRIM(clean_query);

  -- Safety check: only allow SELECT and WITH (CTE)
  upper_query := UPPER(clean_query);
  IF NOT (upper_query LIKE 'SELECT%' OR upper_query LIKE 'WITH%') THEN
    RETURN json_build_object('error', 'Only SELECT queries are allowed');
  END IF;

  -- Block dangerous keywords using word-boundary regex
  IF upper_query ~ '\y(INSERT|UPDATE|DELETE|DROP|ALTER|CREATE|TRUNCATE|GRANT|REVOKE|EXEC|EXECUTE)\y' THEN
    RETURN json_build_object('error', 'Dangerous keywords detected');
  END IF;

  -- Block multiple statements (prevent SQL injection via semicolons)
  IF clean_query LIKE '%;%' THEN
    RETURN json_build_object('error', 'Multiple statements are not allowed');
  END IF;

  -- Execute and return as JSON
  EXECUTE 'SELECT json_agg(row_to_json(t)) FROM (' || clean_query || ') t' INTO result;

  -- Handle null result (no rows)
  IF result IS NULL THEN
    result := '[]'::json;
  END IF;

  RETURN result;
EXCEPTION
  WHEN OTHERS THEN
    RETURN json_build_object('error', SQLERRM);
END;
$function$

CREATE OR REPLACE FUNCTION public.execute_ai_readonly_query(p_query text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SET search_path TO 'public'
AS $function$
declare
  v_sql text := trim(coalesce(p_query, ''));
  v_lower text;
  v_rows jsonb;
  v_row_count integer;
begin
  v_sql := regexp_replace(v_sql, ';\s*$', '');
  v_lower := lower(v_sql);

  if v_sql = '' or v_lower !~ '^\s*(select|with)\s' then
    raise exception 'AI query must be SELECT-only';
  end if;

  if v_sql like '%;%' then
    raise exception 'AI query must contain a single statement';
  end if;

  if v_sql ~ '(--|/\*)' then
    raise exception 'AI query comments are not allowed';
  end if;

  if v_lower ~ '(^|[^a-z_])(insert|update|delete|drop|alter|truncate|grant|revoke|create|replace|merge|call|copy|do|execute|notify|listen|vacuum|analyze|set|reset|refresh)([^a-z_]|$)' then
    raise exception 'AI query contains a blocked keyword';
  end if;

  if v_lower ~ '(^|[^a-z_])(auth|storage|vault|net|extensions|pg_catalog|information_schema)\s*\.' then
    raise exception 'AI query references a blocked schema';
  end if;

  perform set_config('statement_timeout', '5000', true);

  execute format(
    'select coalesce(jsonb_agg(to_jsonb(ai_limited)), ''[]''::jsonb)
       from (select * from (%s) ai_source limit 500) ai_limited',
    v_sql
  )
  into v_rows;

  v_row_count := coalesce(jsonb_array_length(v_rows), 0);
  return jsonb_build_object(
    'rows', v_rows,
    'rowCount', v_row_count,
    'limited', v_row_count >= 500
  );
end;
$function$

CREATE OR REPLACE FUNCTION public.execute_readonly_query(query_text text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  result jsonb;
BEGIN
  -- Only allow SELECT statements
  IF NOT (lower(trim(query_text)) LIKE 'select%' OR lower(trim(query_text)) LIKE 'with%') THEN
    RAISE EXCEPTION 'Only SELECT queries are allowed';
  END IF;

  -- Block dangerous keywords
  IF query_text ~* '\b(insert|update|delete|drop|alter|truncate|create|grant|revoke)\b' THEN
    RAISE EXCEPTION 'Write operations are not allowed';
  END IF;

  EXECUTE 'SELECT jsonb_agg(row_to_json(t)) FROM (' || query_text || ') t' INTO result;
  RETURN COALESCE(result, '[]'::jsonb);
END;
$function$

CREATE OR REPLACE FUNCTION public.get_next_employee_code()
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  next_val INT;
BEGIN
  next_val := nextval('employee_code_seq');
  RETURN 'TT' || LPAD(next_val::TEXT, 3, '0');
END;
$function$

CREATE OR REPLACE FUNCTION public.next_asset_code()
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_next integer;
  v_code text;
begin
  perform pg_advisory_xact_lock(hashtext('public.next_asset_code'));

  select coalesce(max(substring(code from '^TS-([0-9]+)$')::integer), 0) + 1
    into v_next
  from public.assets
  where code ~ '^TS-[0-9]+$';

  loop
    v_code := 'TS-' || lpad(v_next::text, 3, '0');
    exit when not exists (select 1 from public.assets where code = v_code);
    v_next := v_next + 1;
  end loop;

  return v_code;
end;
$function$

CREATE OR REPLACE FUNCTION public.process_request_step(p_request_id uuid, p_user_id uuid, p_action text, p_comment text DEFAULT ''::text)
 RETURNS request_instances
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_req public.request_instances%rowtype;
  v_current_user uuid := public.current_app_user_id();
  v_step jsonb;
  v_step_ord bigint;
  v_approvers jsonb;
  v_all_approved boolean;
  v_status text;
  v_step_order integer;
begin
  if v_current_user is null then
    raise exception 'authentication required';
  end if;
  if p_user_id is distinct from v_current_user and not public.is_module_admin('RQ') then
    raise exception 'cannot act as another user';
  end if;

  select * into v_req
  from public.request_instances
  where id = p_request_id
  for update;
  if not found then
    raise exception 'request not found: %', p_request_id;
  end if;
  if v_req.status not in ('PENDING', 'IN_PROGRESS') then
    raise exception 'request is not waiting for approval';
  end if;

  select elem, ord
    into v_step, v_step_ord
  from jsonb_array_elements(coalesce(v_req.approvers, '[]'::jsonb)) with ordinality as e(elem, ord)
  where elem->>'status' = 'waiting'
  order by coalesce((elem->>'order')::integer, ord::integer)
  limit 1;

  if v_step is null then
    raise exception 'no waiting approver';
  end if;
  if v_step->>'userId' <> p_user_id::text and not public.is_module_admin('RQ') then
    raise exception 'user is not the current approver';
  end if;

  v_step_order := coalesce((v_step->>'order')::integer, v_step_ord::integer);

  if upper(p_action) = 'APPROVED' then
    select jsonb_agg(
      case when ord = v_step_ord then
        elem || jsonb_build_object(
          'status', 'approved',
          'comment', coalesce(nullif(p_comment, ''), 'Đã duyệt'),
          'actedAt', now()::text
        )
      else elem end
      order by ord
    )
      into v_approvers
    from jsonb_array_elements(coalesce(v_req.approvers, '[]'::jsonb)) with ordinality as e(elem, ord);

    v_all_approved := not exists (
      select 1 from jsonb_array_elements(v_approvers) e(elem)
      where elem->>'status' = 'waiting'
    );
    v_status := case when v_all_approved then 'APPROVED' else 'PENDING' end;

    update public.request_instances
    set approvers = v_approvers,
        status = v_status,
        updated_at = now()
    where id = p_request_id
    returning * into v_req;

    insert into public.request_logs(request_id, action, acted_by, comment)
    values (
      p_request_id,
      'APPROVED',
      p_user_id,
      coalesce(nullif(p_comment, ''), 'Duyệt bước ' || v_step_order::text)
    );
  elsif upper(p_action) = 'REJECTED' then
    select jsonb_agg(
      case when ord = v_step_ord then
        elem || jsonb_build_object(
          'status', 'rejected',
          'comment', coalesce(nullif(p_comment, ''), 'Từ chối'),
          'actedAt', now()::text
        )
      else elem end
      order by ord
    )
      into v_approvers
    from jsonb_array_elements(coalesce(v_req.approvers, '[]'::jsonb)) with ordinality as e(elem, ord);

    update public.request_instances
    set approvers = v_approvers,
        status = 'REJECTED',
        updated_at = now()
    where id = p_request_id
    returning * into v_req;

    insert into public.request_logs(request_id, action, acted_by, comment)
    values (
      p_request_id,
      'REJECTED',
      p_user_id,
      coalesce(nullif(p_comment, ''), 'Từ chối ở bước ' || v_step_order::text)
    );
  else
    raise exception 'unsupported request action: %', p_action;
  end if;

  return v_req;
end;
$function$

CREATE OR REPLACE FUNCTION public.process_transaction_status(p_transaction_id text, p_status transaction_status, p_approver_id uuid)
 RETURNS transactions
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_tx public.transactions%rowtype;
  v_user public.users%rowtype;
  v_line jsonb;
  v_pending jsonb;
  v_item_id text;
  v_qty integer;
  v_can_approve boolean := false;
  v_can_complete boolean := false;
begin
  select * into v_tx
  from public.transactions
  where id = p_transaction_id
  for update;
  if not found then
    raise exception 'transaction not found: %', p_transaction_id;
  end if;

  select * into v_user from public.users where id = public.current_app_user_id();
  if v_user.id is null then
    raise exception 'authentication required';
  end if;

  v_can_approve :=
    public.is_module_admin('WMS')
    or (
      v_user.role = 'WAREHOUSE_KEEPER'
      and (
        v_user.assigned_warehouse_id is null
        or (v_tx.type = 'IMPORT'::public.transaction_type and v_user.assigned_warehouse_id is not distinct from v_tx.target_warehouse_id)
        or (v_tx.type in ('EXPORT'::public.transaction_type, 'LIQUIDATION'::public.transaction_type, 'TRANSFER'::public.transaction_type)
            and v_user.assigned_warehouse_id is not distinct from v_tx.source_warehouse_id)
      )
    );

  v_can_complete :=
    public.is_module_admin('WMS')
    or (
      v_user.role = 'WAREHOUSE_KEEPER'
      and (
        v_user.assigned_warehouse_id is null
        or (v_tx.type in ('IMPORT'::public.transaction_type, 'TRANSFER'::public.transaction_type)
            and v_user.assigned_warehouse_id is not distinct from v_tx.target_warehouse_id)
        or (v_tx.type in ('EXPORT'::public.transaction_type, 'LIQUIDATION'::public.transaction_type)
            and v_user.assigned_warehouse_id is not distinct from v_tx.source_warehouse_id)
      )
    );

  if p_status = 'APPROVED'::public.transaction_status and not v_can_approve then
    raise exception 'insufficient privilege to approve transaction';
  end if;

  if p_status = 'CANCELLED'::public.transaction_status
     and not v_can_approve
     and v_tx.requester_id is distinct from v_user.id then
    raise exception 'insufficient privilege to cancel transaction';
  end if;

  if p_status = 'COMPLETED'::public.transaction_status and not v_can_complete then
    raise exception 'insufficient privilege to complete transaction';
  end if;

  if v_tx.status = p_status then
    return v_tx;
  end if;
  if v_tx.status = 'CANCELLED'::public.transaction_status then
    raise exception 'cancelled transaction cannot be changed';
  end if;
  if v_tx.status = 'COMPLETED'::public.transaction_status then
    raise exception 'completed transaction cannot be changed';
  end if;

  if p_status in ('APPROVED'::public.transaction_status, 'COMPLETED'::public.transaction_status) then
    for v_pending in
      select value from jsonb_array_elements(coalesce(v_tx.pending_items, '[]'::jsonb))
    loop
      insert into public.items (
        id, sku, name, category, unit, purchase_unit,
        price_in, price_out, min_stock, supplier_id, image_url,
        stock_by_warehouse, location
      )
      values (
        v_pending->>'id',
        v_pending->>'sku',
        v_pending->>'name',
        coalesce(nullif(v_pending->>'category', ''), 'Khác'),
        coalesce(nullif(v_pending->>'unit', ''), 'Cái'),
        nullif(v_pending->>'purchaseUnit', ''),
        coalesce(nullif(v_pending->>'priceIn', '')::numeric, 0),
        coalesce(nullif(v_pending->>'priceOut', '')::numeric, 0),
        coalesce(nullif(v_pending->>'minStock', '')::integer, 0),
        nullif(v_pending->>'supplierId', ''),
        nullif(v_pending->>'imageUrl', ''),
        coalesce(v_pending->'stockByWarehouse', '{}'::jsonb),
        nullif(v_pending->>'location', '')
      )
      on conflict (id) do nothing;
    end loop;
  end if;

  if p_status = 'COMPLETED'::public.transaction_status then
    for v_line in
      select value from jsonb_array_elements(v_tx.items)
    loop
      v_item_id := v_line->>'itemId';
      v_qty := coalesce(nullif(v_line->>'quantity', '')::numeric, 0)::integer;
      if v_item_id is null or v_qty <= 0 then
        raise exception 'invalid transaction item payload';
      end if;

      if v_tx.type = 'IMPORT'::public.transaction_type then
        perform public.apply_stock_change(v_item_id, v_tx.target_warehouse_id, v_qty);
      elsif v_tx.type in ('EXPORT'::public.transaction_type, 'LIQUIDATION'::public.transaction_type) then
        perform public.apply_stock_change(v_item_id, v_tx.source_warehouse_id, -v_qty);
      elsif v_tx.type = 'TRANSFER'::public.transaction_type then
        perform public.apply_stock_change(v_item_id, v_tx.source_warehouse_id, -v_qty);
        perform public.apply_stock_change(v_item_id, v_tx.target_warehouse_id, v_qty);
      elsif v_tx.type = 'ADJUSTMENT'::public.transaction_type then
        perform public.apply_stock_change(v_item_id, v_tx.target_warehouse_id, v_qty);
      end if;
    end loop;
  end if;

  update public.transactions
  set status = p_status,
      approver_id = p_approver_id
  where id = p_transaction_id
  returning * into v_tx;

  return v_tx;
end;
$function$

CREATE OR REPLACE FUNCTION public.process_workflow_instance(p_instance_id uuid, p_action workflow_instance_action, p_user_id uuid, p_comment text DEFAULT ''::text)
 RETURNS workflow_instances
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_inst public.workflow_instances%rowtype;
  v_current_user uuid := public.current_app_user_id();
  v_next_node_id uuid;
  v_next_node_type public.workflow_node_type;
  v_prev_node_id uuid;
  v_prev_node_type public.workflow_node_type;
begin
  if v_current_user is null then
    raise exception 'authentication required';
  end if;
  if p_user_id is distinct from v_current_user and not public.is_module_admin('WF') then
    raise exception 'cannot act as another user';
  end if;

  select * into v_inst
  from public.workflow_instances
  where id = p_instance_id
  for update;
  if not found then
    raise exception 'workflow instance not found: %', p_instance_id;
  end if;
  if v_inst.status <> 'RUNNING'::public.workflow_instance_status then
    raise exception 'workflow instance is not running';
  end if;
  if v_inst.current_node_id is null then
    raise exception 'workflow instance has no current node';
  end if;

  insert into public.workflow_instance_logs(instance_id, node_id, action, acted_by, comment)
  values (p_instance_id, v_inst.current_node_id, p_action, p_user_id, coalesce(p_comment, ''));

  if p_action = 'APPROVED'::public.workflow_instance_action then
    select e.target_node_id, n.type
      into v_next_node_id, v_next_node_type
    from public.workflow_edges e
    join public.workflow_nodes n on n.id = e.target_node_id
    where e.source_node_id = v_inst.current_node_id
    limit 1;

    if v_next_node_id is null then
      raise exception 'no next workflow node found';
    end if;

    update public.workflow_instances
    set current_node_id = v_next_node_id,
        status = case
          when v_next_node_type = 'END'::public.workflow_node_type
          then 'COMPLETED'::public.workflow_instance_status
          else status
        end,
        updated_at = now()
    where id = p_instance_id
    returning * into v_inst;
  elsif p_action = 'REJECTED'::public.workflow_instance_action then
    update public.workflow_instances
    set status = 'REJECTED'::public.workflow_instance_status,
        updated_at = now()
    where id = p_instance_id
    returning * into v_inst;
  elsif p_action = 'REVISION_REQUESTED'::public.workflow_instance_action then
    select e.source_node_id, n.type
      into v_prev_node_id, v_prev_node_type
    from public.workflow_edges e
    join public.workflow_nodes n on n.id = e.source_node_id
    where e.target_node_id = v_inst.current_node_id
    limit 1;

    if v_prev_node_id is not null and v_prev_node_type = 'START'::public.workflow_node_type then
      select e.target_node_id
        into v_prev_node_id
      from public.workflow_edges e
      where e.source_node_id = v_prev_node_id
      limit 1;
    end if;

    if v_prev_node_id is not null then
      update public.workflow_instances
      set current_node_id = v_prev_node_id,
          updated_at = now()
      where id = p_instance_id
      returning * into v_inst;
    end if;
  end if;

  return v_inst;
end;
$function$

CREATE OR REPLACE FUNCTION public.process_workflow_instance_fast(p_instance_id uuid, p_action workflow_instance_action, p_user_id uuid, p_comment text DEFAULT ''::text, p_next_assignee_user_id uuid DEFAULT NULL::uuid)
 RETURNS TABLE(id uuid, template_id uuid, code text, title text, created_by uuid, current_node_id uuid, status workflow_instance_status, watchers text[], step_assignees jsonb, created_at timestamp with time zone, updated_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_inst public.workflow_instances%rowtype;
  v_current_user uuid := public.current_app_user_id();
  v_actor public.users%rowtype;
  v_template public.workflow_templates%rowtype;
  v_current_node public.workflow_nodes%rowtype;
  v_next_node_id uuid;
  v_next_node_type public.workflow_node_type;
  v_prev_node_id uuid;
  v_prev_node_type public.workflow_node_type;
  v_start_node_id uuid;
  v_first_task_node_id uuid;
  v_can_act boolean := false;
begin
  if v_current_user is null then
    raise exception 'authentication required';
  end if;

  if p_user_id is distinct from v_current_user and not public.is_module_admin('WF') then
    raise exception 'cannot act as another user';
  end if;

  select u.* into v_actor
  from public.users u
  where u.id = p_user_id;

  select wi.* into v_inst
  from public.workflow_instances wi
  where wi.id = p_instance_id
  for update;

  if not found then
    raise exception 'workflow instance not found: %', p_instance_id;
  end if;

  if v_inst.status <> 'RUNNING'::public.workflow_instance_status then
    raise exception 'workflow instance is not running';
  end if;

  if v_inst.current_node_id is null then
    raise exception 'workflow instance has no current node';
  end if;

  select wn.* into v_current_node
  from public.workflow_nodes wn
  where wn.id = v_inst.current_node_id;

  if not found then
    raise exception 'workflow current node not found: %', v_inst.current_node_id;
  end if;

  select wt.* into v_template
  from public.workflow_templates wt
  where wt.id = v_inst.template_id;

  if not found then
    raise exception 'workflow template not found: %', v_inst.template_id;
  end if;

  select n.id into v_start_node_id
  from public.workflow_nodes n
  where n.template_id = v_inst.template_id
    and n.type = 'START'::public.workflow_node_type
  limit 1;

  select e.target_node_id into v_first_task_node_id
  from public.workflow_edges e
  where e.source_node_id = v_start_node_id
  limit 1;

  v_can_act :=
    public.is_module_admin('WF')
    or coalesce(v_inst.step_assignees ->> v_inst.current_node_id::text, '') = p_user_id::text
    or coalesce(v_current_node.config ->> 'assigneeUserId', '') = p_user_id::text
    or (
      v_actor.id is not null
      and coalesce(v_current_node.config ->> 'assigneeRole', '') = v_actor.role::text
    )
    or p_user_id::text = any(coalesce(v_template.managers, '{}'::text[]))
    or (
      v_inst.created_by = p_user_id
      and v_inst.current_node_id = v_first_task_node_id
      and exists (
        select 1
        from public.workflow_instance_logs wil
        where wil.instance_id = p_instance_id
          and wil.action = 'REVISION_REQUESTED'::public.workflow_instance_action
      )
    );

  if not v_can_act then
    raise exception 'user is not allowed to process current workflow step';
  end if;

  insert into public.workflow_instance_logs(instance_id, node_id, action, acted_by, comment)
  values (p_instance_id, v_inst.current_node_id, p_action, p_user_id, coalesce(p_comment, ''));

  if p_action = 'APPROVED'::public.workflow_instance_action then
    select e.target_node_id, n.type
      into v_next_node_id, v_next_node_type
    from public.workflow_edges e
    join public.workflow_nodes n on n.id = e.target_node_id
    where e.source_node_id = v_inst.current_node_id
    limit 1;

    if v_next_node_id is null then
      raise exception 'no next workflow node found';
    end if;

    update public.workflow_instances wi
    set current_node_id = v_next_node_id,
        status = case
          when v_next_node_type = 'END'::public.workflow_node_type
          then 'COMPLETED'::public.workflow_instance_status
          else wi.status
        end,
        step_assignees = case
          when p_next_assignee_user_id is not null and v_next_node_type <> 'END'::public.workflow_node_type
          then coalesce(wi.step_assignees, '{}'::jsonb) || jsonb_build_object(v_next_node_id::text, p_next_assignee_user_id::text)
          else coalesce(wi.step_assignees, '{}'::jsonb)
        end,
        updated_at = now()
    where wi.id = p_instance_id
    returning wi.* into v_inst;
  elsif p_action = 'REJECTED'::public.workflow_instance_action then
    update public.workflow_instances wi
    set status = 'REJECTED'::public.workflow_instance_status,
        updated_at = now()
    where wi.id = p_instance_id
    returning wi.* into v_inst;
  elsif p_action = 'REVISION_REQUESTED'::public.workflow_instance_action then
    select e.source_node_id, n.type
      into v_prev_node_id, v_prev_node_type
    from public.workflow_edges e
    join public.workflow_nodes n on n.id = e.source_node_id
    where e.target_node_id = v_inst.current_node_id
    limit 1;

    if v_prev_node_id is not null and v_prev_node_type = 'START'::public.workflow_node_type then
      select e.target_node_id
        into v_prev_node_id
      from public.workflow_edges e
      where e.source_node_id = v_prev_node_id
      limit 1;
    end if;

    if v_prev_node_id is not null then
      update public.workflow_instances wi
      set current_node_id = v_prev_node_id,
          step_assignees = case
            when p_next_assignee_user_id is not null
            then coalesce(wi.step_assignees, '{}'::jsonb) || jsonb_build_object(v_prev_node_id::text, p_next_assignee_user_id::text)
            else coalesce(wi.step_assignees, '{}'::jsonb)
          end,
          updated_at = now()
      where wi.id = p_instance_id
      returning wi.* into v_inst;
    end if;
  end if;

  return query select
    v_inst.id,
    v_inst.template_id,
    v_inst.code,
    v_inst.title,
    v_inst.created_by,
    v_inst.current_node_id,
    v_inst.status,
    coalesce(v_inst.watchers, '{}'::text[]),
    coalesce(v_inst.step_assignees, '{}'::jsonb),
    v_inst.created_at,
    v_inst.updated_at;
end;
$function$

