CREATE OR REPLACE FUNCTION public.transfer_asset_stock(p_asset_id text, p_from_stock_id text, p_qty integer, p_to_warehouse_id text DEFAULT NULL::text, p_to_user_id text DEFAULT NULL::text, p_reason text DEFAULT NULL::text, p_date text DEFAULT NULL::text)
 RETURNS asset_transfers
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_from public.asset_location_stocks%rowtype;
  v_target_id text;
  v_asset public.assets%rowtype;
  v_transfer public.asset_transfers%rowtype;
  v_user public.users%rowtype;
  v_to_user_name text;
  v_from_label text;
  v_to_label text;
begin
  if not public.is_module_admin('TS') then
    raise exception 'insufficient privilege to transfer asset stock';
  end if;
  if p_qty <= 0 then
    raise exception 'transfer quantity must be positive';
  end if;
  if nullif(p_to_warehouse_id, '') is null and nullif(p_to_user_id, '') is null then
    raise exception 'destination is required';
  end if;

  select * into v_from
  from public.asset_location_stocks
  where id = p_from_stock_id and asset_id = p_asset_id
  for update;
  if not found then
    raise exception 'source stock not found';
  end if;
  if v_from.qty < p_qty then
    raise exception 'insufficient asset stock: available %, requested %', v_from.qty, p_qty;
  end if;

  select * into v_asset from public.assets where id = p_asset_id;
  if not found then
    raise exception 'asset not found';
  end if;

  select * into v_user from public.users where id = public.current_app_user_id();
  select name into v_to_user_name from public.users where id::text = nullif(p_to_user_id, '');

  update public.asset_location_stocks
  set qty = qty - p_qty,
      updated_at = now()
  where id = p_from_stock_id;

  select id into v_target_id
  from public.asset_location_stocks
  where asset_id = p_asset_id
    and warehouse_id is not distinct from nullif(p_to_warehouse_id, '')
    and assigned_to_user_id is not distinct from nullif(p_to_user_id, '')
  limit 1
  for update;

  if v_target_id is null then
    insert into public.asset_location_stocks (
      asset_id, warehouse_id, qty, assigned_to_user_id, assigned_to_name, updated_at
    )
    values (
      p_asset_id, nullif(p_to_warehouse_id, ''), p_qty,
      nullif(p_to_user_id, ''), v_to_user_name, now()
    );
  else
    update public.asset_location_stocks
    set qty = qty + p_qty,
        assigned_to_name = coalesce(v_to_user_name, assigned_to_name),
        updated_at = now()
    where id = v_target_id;
  end if;

  select coalesce(v_from.assigned_to_name, w.name, 'Không xác định')
    into v_from_label
  from (select 1) s
  left join public.warehouses w on w.id = v_from.warehouse_id;

  select coalesce(v_to_user_name, w.name, 'Không xác định')
    into v_to_label
  from (select 1) s
  left join public.warehouses w on w.id = nullif(p_to_warehouse_id, '');

  insert into public.asset_transfers (
    code, asset_id, asset_code, asset_name, qty,
    from_warehouse_id, from_location_label,
    to_warehouse_id, to_location_label,
    received_by_user_id, received_by_name,
    date, reason, status, performed_by, performed_by_name, created_at
  )
  values (
    public.next_asset_transfer_code(), p_asset_id, v_asset.code, v_asset.name, p_qty,
    v_from.warehouse_id, v_from_label,
    nullif(p_to_warehouse_id, ''), v_to_label,
    nullif(p_to_user_id, ''), v_to_user_name,
    coalesce(nullif(p_date, ''), now()::date::text), p_reason, 'completed',
    public.current_app_user_id()::text, coalesce(v_user.name, v_user.username), now()
  )
  returning * into v_transfer;

  return v_transfer;
end;
$function$

CREATE OR REPLACE FUNCTION public.transition_daily_log_status(p_log_id text, p_status text, p_requested_verifier_id text DEFAULT NULL::text, p_requested_verifier_name text DEFAULT NULL::text, p_rejection_reason text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  v_log public.daily_logs%rowtype;
  v_user_id text := public.current_app_user_id()::text;
  v_is_admin boolean := public.is_admin();
  v_actor_name text;
  v_owner_id text;
  v_target_verifier_id text;
  v_can_verify boolean;
begin
  if v_user_id is null then
    raise exception 'Không xác định được người dùng đang thao tác.';
  end if;

  if p_status not in ('submitted', 'verified', 'rejected') then
    raise exception 'Trạng thái nhật ký không hợp lệ: %', p_status;
  end if;

  select *
  into v_log
  from public.daily_logs
  where id = p_log_id
  for update;

  if not found then
    raise exception 'Không tìm thấy nhật ký công trường.';
  end if;

  select coalesce(u.name, u.username, u.email, u.id::text)
  into v_actor_name
  from public.users u
  where u.id::text = v_user_id;

  v_owner_id := coalesce(v_log.created_by_id, v_log.submitted_by_id, v_log.submitted_by);
  v_target_verifier_id := coalesce(v_log.requested_verifier_id, v_log.submitted_to_user_id);

  if p_status = 'submitted' then
    if coalesce(v_log.status, 'draft') not in ('draft', 'rejected') then
      raise exception 'Chỉ nhật ký nháp hoặc bị trả lại mới được gửi xác nhận.';
    end if;

    if not v_is_admin and coalesce(v_owner_id, '') <> v_user_id then
      raise exception 'Chỉ người lập nhật ký mới được gửi xác nhận.';
    end if;

    if nullif(p_requested_verifier_id, '') is null then
      raise exception 'Vui lòng chọn người xác nhận nhật ký.';
    end if;

    if p_requested_verifier_id = v_user_id and not v_is_admin then
      raise exception 'Người xác nhận phải khác người gửi.';
    end if;

    if not public.daily_log_user_has_project_permission(
      p_requested_verifier_id,
      v_log.project_id::text,
      v_log.construction_site_id::text,
      'verify'
    ) then
      raise exception 'Người được chọn chưa có quyền verify trong Tổ chức dự án.';
    end if;

    update public.daily_logs
    set
      status = 'submitted',
      verified = false,
      submitted_by = v_user_id,
      submitted_by_id = v_user_id,
      submitted_at = now(),
      requested_verifier_id = p_requested_verifier_id,
      submitted_to_user_id = p_requested_verifier_id,
      requested_verifier_name = nullif(p_requested_verifier_name, ''),
      rejected_by = null,
      rejected_by_id = null,
      rejected_at = null,
      rejection_reason = null
    where id = p_log_id;

    return;
  end if;

  if coalesce(v_log.status, 'draft') <> 'submitted' then
    raise exception 'Chỉ nhật ký đang chờ xác nhận mới được duyệt hoặc trả lại.';
  end if;

  v_can_verify := v_is_admin
    or (
      nullif(v_target_verifier_id, '') is not null
      and v_target_verifier_id = v_user_id
      and public.daily_log_user_has_project_permission(
        v_user_id,
        v_log.project_id::text,
        v_log.construction_site_id::text,
        'verify'
      )
    )
    or (
      nullif(v_target_verifier_id, '') is null
      and public.daily_log_user_has_project_permission(
        v_user_id,
        v_log.project_id::text,
        v_log.construction_site_id::text,
        'verify'
      )
    );

  if not v_can_verify then
    raise exception 'Bạn không phải người được giao xác nhận nhật ký này.';
  end if;

  if p_status = 'verified' then
    update public.daily_logs
    set
      status = 'verified',
      verified = true,
      verified_by = coalesce(v_actor_name, v_user_id),
      verified_by_id = v_user_id,
      verified_at = now(),
      rejected_by = null,
      rejected_by_id = null,
      rejected_at = null,
      rejection_reason = null
    where id = p_log_id;
  else
    update public.daily_logs
    set
      status = 'rejected',
      verified = false,
      rejected_by = coalesce(v_actor_name, v_user_id),
      rejected_by_id = v_user_id,
      rejected_at = now(),
      rejection_reason = coalesce(nullif(p_rejection_reason, ''), 'Cần bổ sung/kiểm tra lại')
    where id = p_log_id;
  end if;
end;
$function$

